function esc(n){return String(n??"").replace(/"/g,"&quot;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}function buildAgentCard(n){const a=(n.name[0]||"")+(n.last[0]||""),e=AVATAR_BG[n.id%AVATAR_BG.length],t=esc(n.name),s=esc(n.last),i=esc(n.specialty||""),r=esc(n.bio||""),d=n.avatar?`<img src="${n.avatar}" alt="${t} ${s}"\n            class="agent-avatar-img"\n            onerror="this.style.display='none';this.nextElementSibling.style.display='flex'"/>\n       <div class="agent-avatar" style="background:${e};display:none">${a}</div>`:`<div class="agent-avatar" style="background:${e}">${a}</div>`,l=n.whatsapp?`<a href="https://wa.me/${n.whatsapp}?text=Hola%20${encodeURIComponent(n.name)}%2C%20te%20contacto%20desde%20Bienenhaus."\n           target="_blank" class="btn btn-outline btn-sm">WhatsApp</a>`:"",c=n.email?`<a href="mailto:${n.email}" class="btn btn-ghost btn-sm">Contactar</a>`:n.phone?`<a href="tel:${n.phone}" class="btn btn-ghost btn-sm">Llamar</a>`:"";return`\n    <div class="agent-card">\n      <div class="agent-avatar-wrap">\n        ${d}\n      </div>\n      <div class="agent-name">${t} ${s}</div>\n      ${i?`<div class="agent-specialty">${i}</div>`:""}\n      <div class="agent-years">${n.license_number||`${n.years} año${1!==n.years?"s":""} de experiencia`}</div>\n      ${r?`<div class="agent-bio">${r}</div>`:""}\n      <div class="agent-ctas">\n        ${c}\n        ${l}\n      </div>\n    </div>`}function renderAgents(n){const a=document.getElementById("agentsGrid");n.length?a.innerHTML=n.map(buildAgentCard).join(""):a.innerHTML='<div class="loading-state">No hay agentes registrados.</div>'}async function loadAgents(){try{const n=await API.getAgents();return renderAgents(n),n}catch(n){return document.getElementById("agentsGrid").innerHTML='<div class="loading-state">Error al cargar agentes.</div>',console.warn(n),[]}}window.loadAgents=loadAgents,window.renderAgents=renderAgents,window.buildAgentCard=buildAgentCard;